// Generated by Claude Sonnet 4.5

import { BackupConfig, BackupInfo, BackupItem, helpers } from '@eclipse-che/common';

import { AxiosWrapper } from '@/services/axios-wrapper/axiosWrapper';
import { dashboardBackendPrefix } from '@/services/backend-client/const';

/**
 * Get cluster-wide backup configuration
 *
 * @param namespace - Kubernetes namespace (for auth routing)
 * @returns BackupConfig with schedule, registry, and enabled flag
 */
export async function getBackupConfig(namespace: string): Promise<BackupConfig> {
  try {
    const response = await AxiosWrapper.createToRetryMissedBearerTokenError().get<BackupConfig>(
      `${dashboardBackendPrefix}/namespace/${namespace}/backup-config`,
    );
    return response.data;
  } catch (e) {
    throw new Error(`Failed to fetch backup configuration. ${helpers.errors.getMessage(e)}`);
  }
}

/**
 * Get backup status for a specific workspace
 *
 * @param namespace - Kubernetes namespace
 * @param workspaceName - DevWorkspace name
 * @returns BackupInfo with status, timestamps, and backup URL
 */
export async function getWorkspaceBackupStatus(
  namespace: string,
  workspaceName: string,
): Promise<BackupInfo> {
  try {
    const response = await AxiosWrapper.createToRetryMissedBearerTokenError().get<BackupInfo>(
      `${dashboardBackendPrefix}/namespace/${namespace}/devworkspaces/${workspaceName}/backup-status`,
    );
    return response.data;
  } catch (e) {
    throw new Error(
      `Failed to fetch backup status for workspace '${workspaceName}'. ${helpers.errors.getMessage(e)}`,
    );
  }
}

/**
 * List all backup images for a namespace with optional workspace name filter
 *
 * @param namespace - Kubernetes namespace
 * @param workspaceName - Optional workspace name filter
 * @returns List of backup images
 */
export async function listBackups(
  namespace: string,
  workspaceName?: string,
): Promise<BackupItem[]> {
  try {
    const response = await AxiosWrapper.createToRetryMissedBearerTokenError().get<BackupItem[]>(
      `${dashboardBackendPrefix}/namespace/${namespace}/backups`,
      {
        params: { workspaceName },
      },
    );
    return response.data;
  } catch (e) {
    throw new Error(
      `Failed to list backups for namespace '${namespace}'. ${helpers.errors.getMessage(e)}`,
    );
  }
}
